function solve(nums) {
    const n = nums.length;
    if (n <= 1) {
        return 0;
    }

    // The goal is to make nums[i] <= nums[i+1] for all 0 <= i < n-1.
    // If nums[i] > nums[i+1], we must increase nums[i+1] (and potentially elements before it)
    // or decrease nums[i] (which is not allowed, only positive increments are allowed).
    // Since we can only increase elements by adding positive x to a subsegment,
    // the constraint violation nums[i] > nums[i+1] implies that nums[i+1] needs to be increased
    // relative to nums[i].

    // Consider the difference d_i = nums[i] - nums[i+1]. If d_i > 0, we have a violation.
    // We need to apply operations such that the new difference d'_i <= 0.

    // Let S be the total sum of all x values used across all operations.
    // An operation adds x to a subsegment [l, r].

    // Let's look at the required change at each adjacent pair.
    // For nums[i] <= nums[i+1] to hold, we need nums[i+1]' >= nums[i]'.
    // The most critical constraint comes from the immediate requirement at each index i:
    // New nums[i+1] >= New nums[i].

    // If nums[i] > nums[i+1], we need at least (nums[i] - nums[i+1]) to be added to nums[i+1]
    // (or elements after it, provided nums[i] is not increased more).

    // Since we want the minimum total sum of x, we should aim for the smallest necessary increases.
    // The most localized fix for nums[i] > nums[i+1] is to ensure the increase applied to nums[i+1]
    // is at least nums[i] - nums[i+1] more than the increase applied to nums[i].

    // Crucially, if we apply an operation adding x to [l, r]:
    // - If i < l or i >= r: nums[i] and nums[i+1] are either both unchanged, or both increased by x. Their difference remains the same.
    // - If l <= i < r: nums[i] increases by x, nums[i+1] increases by x. Difference remains the same.
    // - If i = l-1 and i+1 = l (i.e., i+1 is the start): nums[i] unchanged, nums[i+1] increases by x. Difference decreases by x.
    // - If i = r and i+1 = r+1 (i.e., i is the end): nums[i] increases by x, nums[i+1] unchanged. Difference increases by x.
    // - If l <= i < r-1: Both increase by x. Difference unchanged.
    // - If i = r-1 and i+1 = r: nums[i] increases by x, nums[i+1] unchanged. Difference increases by x.

    // To fix nums[i] > nums[i+1], we need the difference nums[i] - nums[i+1] to become <= 0.
    // The most effective operation to reduce the gap (nums[i] - nums[i+1]) is to apply an increase x to a segment starting at i+1, and not including i.
    // E.g., add x to [i+1, r]. This increases nums[i+1] by x, and nums[i] is unchanged (assuming i < i+1).
    // The new gap is (nums[i]) - (nums[i+1] + x) = (nums[i] - nums[i+1]) - x.
    // We need x >= nums[i] - nums[i+1]. The minimum such x is nums[i] - nums[i+1].

    // If we only perform these targeted operations:
    // For every i where nums[i] > nums[i+1], we must perform at least one operation of value x = nums[i] - nums[i+1] on a segment starting at i+1.
    // Since the required increases are independent (fixing one violation doesn't necessarily fix or break others in a predictable way without considering global effects),
    // the minimum total sum of x must be the sum of minimum required fixes for each adjacent pair that violates the non-decreasing property.

    let totalSumOfX = 0;

    for (let i = 0; i < n - 1; i++) {
        if (nums[i] > nums[i+1]) {
            // We need to increase nums[i+1] relative to nums[i] by at least D = nums[i] - nums[i+1].
            // The minimum required x for this specific gap is D.
            const difference = nums[i] - nums[i+1];
            totalSumOfX += difference;
        }
    }

    return totalSumOfX;
