fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n <= 1 {
        return 0;
    }

    // The problem asks for the minimum sum of all 'x' values used in operations
    // such that the final array is non-decreasing.
    // An operation adds a positive integer x to a subsegment nums[l..r].

    // Consider any adjacent pair (nums[i], nums[i+1]). For the final array to be non-decreasing,
    // we must have nums'[i] <= nums'[i+1], where nums' are the elements after all operations.

    // If nums[i] <= nums[i+1], this pair is fine initially.
    // If nums[i] > nums[i+1], we have a violation. We need to increase nums[i+1] relative to nums[i].
    // The minimum relative increase required at this specific boundary is D = nums[i] - nums[i+1].

    // If we perform an operation adding x to [l, r]:
    // 1. If l <= i < i+1 <= r, both increase by x, difference unchanged.
    // 2. If i+1 = l (i.e., the operation starts at i+1, and i is outside): nums[i] is unchanged, nums[i+1] increases by x.
    //    The difference decreases by x.
    // 3. If i = r (i.e., the operation ends at i, and i+1 is outside): nums[i] increases by x, nums[i+1] is unchanged.
    //    The difference increases by x.

    // To achieve the minimum total sum of x, we should assume that each required relative increase
    // is achieved by a minimal, targeted operation.
    // For every i where nums[i] > nums[i+1], we need a net increase of at least D = nums[i] - nums[i+1]
    // on nums[i+1] compared to nums[i]. The most direct way to account for this in the total sum
    // is to sum up these required deficits. If we apply an operation of value D starting at i+1,
    // this accounts for D in the total sum, and satisfies the local constraint at i, i+1.

    let mut total_sum_of_x: i64 = 0;

    for i in 0..(n - 1) {
        if nums[i] > nums[i + 1] {
            let difference = nums[i] - nums[i + 1];
            // This difference must be covered by the sum of x values applied to segments starting at i+1 or later
            // relative to segments covering i.
            total_sum_of_x += difference;
        }
    }

    total_sum_of_x
}
